import { useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { motion, AnimatePresence } from 'framer-motion'
import './Cartelera.css'

const PELICULAS = [
  { id: 1, titulo: 'Avengers: Doomsday', genero: 'Acción', duracion: '2h 30min', clasificacion: 'PG-13', precio: 18.90, rating: 4.8, idioma: 'Sub/Dob', formato: '2D', estreno: true, imagen: 'data:image/jpeg;base64,' },
  { id: 2, titulo: 'Minecraft: La Película', genero: 'Aventura', duracion: '1h 50min', clasificacion: 'G', precio: 16.90, rating: 4.3, idioma: 'Doblada', formato: '2D', estreno: false, imagen: 'data:image/jpeg;base64,' },
  { id: 7, titulo: 'Sonic 3', genero: 'Animación', duracion: '1h 45min', clasificacion: 'G', precio: 16.90, rating: 4.5, idioma: 'Doblada', formato: '2D', estreno: false, imagen: 'data:image/jpeg;base64,'},
  { id: 4, titulo: 'Thunderbolts', genero: 'Acción', duracion: '2h 10min', clasificacion: 'PG-13', precio: 18.90, rating: 4.4, idioma: 'Subtitulada', formato: 'IMAX', estreno: true, imagen: 'data:image/jpeg;base64,' },
  { id: 5, titulo: 'Lilo & Stitch', genero: 'Familiar', duracion: '1h 55min', clasificacion: 'G', precio: 15.90, rating: 4.6, idioma: 'Doblada', formato: '2D', estreno: false, imagen: 'data:image/jpeg;base64,' },
  { id: 6, titulo: 'Misión Imposible 8', genero: 'Thriller', duracion: '2h 20min', clasificacion: 'PG-13', precio: 19.90, rating: 4.9, idioma: 'Subtitulada', formato: '4DX', estreno: true, imagen: 'data:image/jpeg;base64,' },
  { id: 3, titulo: 'Karate Kid', genero: 'Drama', duracion: '2h 05min', clasificacion: 'PG', precio: 17.90, rating: 4.2, idioma: 'Doblada', formato: '2D', estreno: false, imagen: 'data:image/jpeg;base64,' },
  { id: 8, titulo: 'Destino Final', genero: 'Terror', duracion: '1h 50min', clasificacion: 'R', precio: 18.90, rating: 4.1, idioma: 'Subtitulada', formato: '2D', estreno: false, imagen: 'data:image/jpeg;base64,' },
  { id: 9, titulo: 'Spider-Man: Beyond the Spider-Verse', genero: 'Animación', duracion: '2h 05min', clasificacion: 'PG', precio: 18.90, rating: 4.9, idioma: 'Sub/Dob', formato: 'IMAX', estreno: true, imagen: 'data:image/jpeg;base64,' },
  { id: 10, titulo: 'The Batman II', genero: 'Acción', duracion: '2h 40min', clasificacion: 'PG-13', precio: 19.90, rating: 4.7, idioma: 'Subtitulada', formato: '2D', estreno: true, imagen: 'data:image/jpeg;base64,' },
  { id: 11, titulo: 'El Conjuro: Último Caso', genero: 'Terror', duracion: '1h 58min', clasificacion: 'R', precio: 18.90, rating: 4.0, idioma: 'Sub/Dob', formato: '2D', estreno: false, imagen: 'data:image/jpeg;base64,' },
  { id: 12, titulo: 'Intensamente 2', genero: 'Familiar', duracion: '1h 42min', clasificacion: 'G', precio: 16.50, rating: 4.8, idioma: 'Doblada', formato: '2D', estreno: true, imagen: 'data:image/jpeg;base64,' },
]

const GENEROS = ['Todos', 'Acción', 'Aventura', 'Animación', 'Terror', 'Drama', 'Familiar', 'Thriller']

export default function Cartelera() {
  const [generoActivo, setGeneroActivo] = useState('Todos')
  const [busqueda, setBusqueda] = useState('')
  const [orden, setOrden] = useState('popularidad')

  const filtradas = useMemo(() => {
    let lista = PELICULAS.filter(p => {
      const coincideGenero = generoActivo === 'Todos' || p.genero === generoActivo
      const coincideBusqueda =
        p.titulo.toLowerCase().includes(busqueda.toLowerCase()) ||
        p.genero.toLowerCase().includes(busqueda.toLowerCase())
      return coincideGenero && coincideBusqueda
    })

    if (orden === 'precio-asc') {
      lista = [...lista].sort((a, b) => a.precio - b.precio)
    } else if (orden === 'precio-desc') {
      lista = [...lista].sort((a, b) => b.precio - a.precio)
    } else if (orden === 'duracion') {
      lista = [...lista].sort((a, b) => a.duracion.localeCompare(b.duracion))
    } else {
      lista = [...lista].sort((a, b) => b.rating - a.rating)
    }

    return lista
  }, [generoActivo, busqueda, orden])

  const totalEstrenos = PELICULAS.filter(p => p.estreno).length
  const precioPromedio = (
    PELICULAS.reduce((acc, p) => acc + p.precio, 0) / PELICULAS.length
  ).toFixed(2)

  return (
    <div className="cartelera-page">
      <motion.div
        className="cartelera-top"
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.45 }}
      >
        <div className="cartelera-header">
          <div>
            <h1>Cartelera</h1>
            <p className="cartelera-sub">
              Elige tu película, filtra por género y compra tus entradas.
            </p>
          </div>

          <div className="cartelera-tools">
            <div className="buscador-wrap">
              <span className="buscador-icon">🔍</span>
              <input
                type="text"
                placeholder="Buscar película o género..."
                value={busqueda}
                onChange={e => setBusqueda(e.target.value)}
                className="buscador"
              />
            </div>

            <select
              className="orden-select"
              value={orden}
              onChange={e => setOrden(e.target.value)}
            >
              <option value="popularidad">Más populares</option>
              <option value="precio-asc">Menor precio</option>
              <option value="precio-desc">Mayor precio</option>
              <option value="duracion">Duración</option>
            </select>
          </div>
        </div>

        <div className="cartelera-stats">
          <div className="stat-box">
            <span className="stat-label">Películas</span>
            <strong>{PELICULAS.length}</strong>
          </div>
          <div className="stat-box">
            <span className="stat-label">Estrenos</span>
            <strong>{totalEstrenos}</strong>
          </div>
          <div className="stat-box">
            <span className="stat-label">Mostradas</span>
            <strong>{filtradas.length}</strong>
          </div>
          <div className="stat-box">
            <span className="stat-label">Desde</span>
            <strong>S/. {Math.min(...PELICULAS.map(p => p.precio)).toFixed(2)}</strong>
          </div>
          <div className="stat-box">
            <span className="stat-label">Promedio</span>
            <strong>S/. {precioPromedio}</strong>
          </div>
        </div>
      </motion.div>

      <motion.div
        className="filtros"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.15 }}
      >
        {GENEROS.map((g, i) => (
          <motion.button
            key={g}
            className={`filtro-btn ${generoActivo === g ? 'activo' : ''}`}
            onClick={() => setGeneroActivo(g)}
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.04 }}
            whileHover={{ scale: 1.06 }}
            whileTap={{ scale: 0.96 }}
          >
            {g}
          </motion.button>
        ))}
      </motion.div>

      <div className="resultados-bar">
        <span>
          {filtradas.length} resultado{filtradas.length !== 1 ? 's' : ''}
        </span>
        <span className="resultados-extra">
          {generoActivo === 'Todos' ? 'Todos los géneros' : generoActivo}
        </span>
      </div>

      <AnimatePresence mode="wait">
        {filtradas.length === 0 ? (
          <motion.div
            key="empty"
            className="no-resultados"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            <p>😕 No se encontraron películas</p>
          </motion.div>
        ) : (
          <motion.div
            key="grid"
            className="cartelera-grid"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            <AnimatePresence>
              {filtradas.map((p, i) => (
                <motion.div
                  key={p.id}
                  layout
                  initial={{ opacity: 0, scale: 0.88 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.88 }}
                  transition={{ duration: 0.28, delay: i * 0.03 }}
                >
                  <div className="pelicula-card">
                    <div className="pelicula-img-wrap">
                      <img src={p.imagen} alt={p.titulo} />
                      <span className="clasificacion">{p.clasificacion}</span>
                      {p.estreno && <span className="badge-estreno">Estreno</span>}

                      <div className="pelicula-overlay">
                        <Link to={`/pelicula/${p.id}`} className="btn-overlay">
                          Ver detalle
                        </Link>
                      </div>
                    </div>

                    <div className="pelicula-info">
                      <div className="pelicula-topline">
                        <span className="rating">⭐ {p.rating.toFixed(1)}</span>
                        <span className="formato">{p.formato}</span>
                      </div>

                      <h3>{p.titulo}</h3>

                      <div className="pelicula-meta">
                        <span className="genero-tag">{p.genero}</span>
                        <span className="duracion">🕐 {p.duracion}</span>
                      </div>

                      <div className="pelicula-extra">
                        <span>{p.idioma}</span>
                        <span>{p.clasificacion}</span>
                      </div>

                      <div className="pelicula-footer">
                        <div className="precio-box">
                          <span className="precio-label">Desde</span>
                          <span className="precio">S/. {p.precio.toFixed(2)}</span>
                        </div>

                        <div className="pelicula-actions">
                          <Link to={`/pelicula/${p.id}`} className="btn-detalle">
                            Detalle
                          </Link>
                          <Link to={`/pelicula/${p.id}`} className="btn-comprar">
                            Comprar
                          </Link>
                        </div>
                      </div>
                    </div>
                  </div>
                </motion.div>
              ))}
            </AnimatePresence>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}